/* ==== list-record-2: Mover "+ Agregar" arriba de la tabla ==== */
[selector="list-record-2"] .data-table {
  display: flex;
  flex-direction: column;
}

/* 1) Título (si existe) se mantiene primero */
[selector="list-record-2"] .data-table > .row.mb-2.ml-0.mr-0 {
  order: 1;
}

/* 2) El contenedor del botón "+ Agregar" antes de la tabla */
[selector="list-record-2"] .data-table > .d-flex.justify-content-between.align-items-center {
  order: 2;
  width: 100%;
  justify-content: flex-end !important;
  margin: .25rem 0 .5rem;
}

/* Ajuste columnas internas para que no “empujen” el botón */
[selector="list-record-2"] .data-table > .d-flex.justify-content-between.align-items-center > .col {
  flex: 0 0 auto;
  max-width: unset;
}
[selector="list-record-2"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-left {
  display: none;
}
[selector="list-record-2"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-right {
  display: block;
}

/* Botón “Agregar” más visible */
[selector="list-record-2"] .data-table > .d-flex [data-cy="add-row"].btn {
  font-weight: 600;
  border-radius: 6px;
  padding: .35rem .9rem;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  margin: 0 -10px 10px 0;
}

/* 3) La tabla queda tercera */
[selector="list-record-2"] .data-table > table.record-list-table-secondary {
  order: 3;
}

/* (Opcional) separa visualmente el botón de la tabla en desktop */
@media (min-width: 576px) {
  [selector="list-record-2"] .data-table > .d-flex.justify-content-between.align-items-center {
    margin-bottom: .75rem;
  }
}

/* ================================
   1) Encabezado: traducir "Actions" → "Acciones"
================================ */
[selector="list-record-2"] table.record-list-table-secondary thead th.text-right > div {
  position: relative;
  color: transparent; /* oculta el texto original */
}
[selector="list-record-2"] table.record-list-table-secondary thead th.text-right > div::after {
  content: "Acciones";
  position: absolute;
  right: 0; left: auto; top: 0;
  color: #2c3e50;
  font-weight: 600;
  text-align: right;
  width: 100%;
}

/* ================================
   2) Colores de íconos Editar/Eliminar
   (SVG embebidos como )
================================ */
/* EDITAR -> Azul Zurich (#0f4c81) */
[selector="list-record-2"] td[aria-colindex="7"] .actions [title="Editar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(17%) sepia(22%) saturate(2557%) hue-rotate(171deg) brightness(92%) contrast(92%);
}
[selector="list-record-2"] td[aria-colindex="7"] .actions [title="Editar"]:hover img{
  filter: invert(13%) sepia(27%) saturate(2412%) hue-rotate(173deg) brightness(80%) contrast(95%);
  transform: translateY(-1px);
}

/* ELIMINAR -> Rojo (#dc2626) */
[selector="list-record-2"] td[aria-colindex="7"] .actions [title="Eliminar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(14%) sepia(90%) saturate(6268%) hue-rotate(356deg) brightness(90%) contrast(104%);
}
[selector="list-record-2"] td[aria-colindex="7"] .actions [title="Eliminar"]:hover img{
  filter: invert(11%) sepia(93%) saturate(5530%) hue-rotate(355deg) brightness(70%) contrast(110%);
  transform: translateY(-1px);
}

/* Accesibilidad: micro-resalte al enfocar con teclado */
[selector="list-record-2"] td[aria-colindex="7"] .actions .btn:focus img{
  outline: none;
  filter: drop-shadow(0 0 0.25rem rgba(15,76,129,.35));
}

/* ================================
   3) POPOVER dinámico anclado al grupo de acciones
   (reemplaza tu margin-top fijo)
================================ */

/* Asegura que el popover pueda “salirse” visualmente de la celda */
[selector="list-record-2"] td[aria-colindex="7"]{
  overflow: visible; /* para que no lo recorte la celda */
}

/* El contenedor de botones será el ancla de posicionamiento */
[selector="list-record-2"] td[aria-colindex="7"] .actions{
  position: relative; /* ancla */
  z-index: 1;
}

/* Popover colocado respecto a .actions, sin offsets mágicos */
[selector="list-record-2"] td[aria-colindex="7"] .actions .popover-content{
  position: absolute;
  right: 0;
  /* —> mostrar ARRIBA de los botones (no abajo) */
  top: auto;
  bottom: calc(100% + 8px);
  z-index: 2000;

  margin-top: 0 !important;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 10px 12px;
  box-shadow: 0 10px 24px rgba(0,0,0,.12);
  width: max-content;
  max-width: clamp(220px, 40vw, 320px);
}

