[selector="list-record-2"] td[aria-colindex="7"] .actions .popover-content::before{
  content: "";
  position: absolute;
  bottom: -6px;
  right: 14px;
  border-width: 6px;
  border-style: solid;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

/* Variante para mostrarlo hacia arriba cuando no hay espacio abajo */
[selector="list-record-2"] td[aria-colindex="7"] .actions .popover-content.popover--top{
  top: auto;
  bottom: calc(100% + 8px);
}
[selector="list-record-2"] td[aria-colindex="7"] .actions .popover-content.popover--top::before{
  top: auto;
